ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?brand_name ?camera_type ?cinematographer WHERE {
  ?camera a :Camera .
  ?camera p:Brand_Name ?brand_name .
  ?camera p:Camera_Type ?camera_type .
  ?camera p:Cinematographer ?cinematographer .
  ?camera p:Purchase_Year ?purchase_year_o .
}
ORDER BY DESC(?purchase_year_o)
LIMIT 1 }
  component: { SELECT ?brand_name ?cinematographer WHERE {
  ?camera a :Camera .
  ?camera p:Brand_Name ?brand_name .
  ?camera p:Cinematographer ?cinematographer .
  ?camera p:Purchase_Year ?purchase_year_o .
}
ORDER BY DESC(?purchase_year_o)
LIMIT 1 }
  component_2: { SELECT ?camera_type ?cinematographer WHERE {
  ?camera a :Camera .
  ?camera p:Camera_Type ?camera_type .
  ?camera p:Cinematographer ?cinematographer .
  ?camera p:Purchase_Year ?purchase_year_o .
}
ORDER BY DESC(?purchase_year_o)
LIMIT 1 }
}
